package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Avoid shell invocation; pass arguments directly to exec.Command.
	// Use OS-appropriate flags.
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows: -n <count>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux/macOS: -c <count>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	outStr := string(output)
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, outStr)
	}

	// Try to parse Linux/macOS summary:
	// "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
	// or macOS: "round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms"
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s*ms`)
	if m := reUnix.FindStringSubmatch(outStr); len(m) >= 3 {
		avg, perr := strconv.ParseFloat(m[2], 64)
		if perr != nil {
			return 0, fmt.Errorf("failed to convert average latency to float: %w", perr)
		}
		return avg, nil
	}

	// Parse Windows summary:
	// "Average = 23ms" (localized output may differ; this is best-effort)
	reWin := regexp.MustCompile(`(?mi)^\s*Average\s*=\s*([0-9]+)\s*ms\s*$`)
	if m := reWin.FindStringSubmatch(outStr); len(m) >= 2 {
		avg, perr := strconv.ParseFloat(m[1], 64)
		if perr != nil {
			return 0, fmt.Errorf("failed to convert average latency to float: %w", perr)
		}
		return avg, nil
	}

	return 0, errors.New("could not parse average latency from ping output")
}

func main() {
	// Intentionally empty: utility function implementation.
}

