package main

import (
	"bytes"
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
	"time"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
//
// Security notes:
// - Avoids shell execution ("bash -c") to prevent command injection.
// - Validates host to a conservative character set.
// - Bounds count to prevent abuse.
// - Adds a timeout to avoid hanging processes.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	// Prevent resource abuse (e.g., very large counts).
	if count > 20 {
		return 0, errors.New("count too large (max 20)")
	}

	// Conservative host validation: allow IPv4/IPv6 literals and DNS-ish names.
	// (No spaces, no shell metacharacters; we also don't use a shell, but this reduces surprises.)
	hostRe := regexp.MustCompile(`^[a-zA-Z0-9.\-:_]+$`)
	if !hostRe.MatchString(host) {
		return 0, errors.New("invalid host")
	}

	// Use exec.Command without a shell.
	// Linux/macOS: ping -c <count> <host>
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	// Ensure we don't hang indefinitely.
	// Typical ping takes ~1s per packet; add some slack.
	cmdTimeout := time.Duration(count)*2*time.Second + 2*time.Second

	var stdout, stderr bytes.Buffer
	cmd.Stdout = &stdout
	cmd.Stderr = &stderr

	if err := cmd.Start(); err != nil {
		return 0, fmt.Errorf("failed to start ping: %w", err)
	}

	done := make(chan error, 1)
	go func() { done <- cmd.Wait() }()

	select {
	case err := <-done:
		outStr := stdout.String()
		errStr := stderr.String()
		combined := outStr
		if errStr != "" {
			if combined != "" && !strings.HasSuffix(combined, "\n") {
				combined += "\n"
			}
			combined += errStr
		}
		if err != nil {
			return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, combined)
		}
		return parseAvgLatency(combined)
	case <-time.After(cmdTimeout):
		_ = cmd.Process.Kill()
		return 0, errors.New("ping timed out")
	}
}

func parseAvgLatency(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	var statsLine string
	for _, line := range lines {
		// Common formats:
		// Linux: "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
		// BusyBox: "round-trip min/avg/max = 12.345/23.456/34.567 ms"
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}
	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract avg value from either format.
	re := regexp.MustCompile(`(?:rtt|round-trip).*min/avg/max(?:/mdev)?\s*=\s*[\d.]+/([\d.]+)/[\d.]+`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}
	return avg, nil
}

func main() {
	// Intentionally left minimal; MeasureLatency is the utility function.
}

