// It uses the system "ping" command via os/exec.
//
// Notes:
// - On Windows, it parses "Average = Xms" from ping output.
// - On Linux/macOS, it parses "min/avg/max" line and returns the avg value.
// - Requires that "ping" is available in PATH and that ICMP is permitted by the OS/network.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host is required")
	}
	if count <= 0 {
		return 0, errors.New("count must be > 0")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux/macOS: ping -c <count> <host>
		// (On macOS, -c is supported; on Linux, too.)
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		// ping returns non-zero if some packets lost; still may contain stats.
		// We'll try to parse output; if parsing fails, return combined error.
		avg, perr := parsePingAverage(out.String(), runtime.GOOS)
		if perr == nil {
			return avg, nil
		}
		msg := strings.TrimSpace(stderr.String())
		if msg == "" {
			msg = strings.TrimSpace(out.String())
		}
		if msg == "" {
			msg = err.Error()
		}
		return 0, fmt.Errorf("ping failed: %v; output: %s", err, msg)
	}

	avg, err := parsePingAverage(out.String(), runtime.GOOS)
	if err != nil {
		return 0, err
	}
	return avg, nil
}

func parsePingAverage(output string, goos string) (float64, error) {
	if strings.TrimSpace(output) == "" {
		return 0, errors.New("empty ping output")
	}

	if goos == "windows" {
		// Typical Windows summary:
		// Minimum = 1ms, Maximum = 3ms, Average = 2ms
		re := regexp.MustCompile(`(?i)Average\s*=\s*([0-9]+)\s*ms`)
		m := re.FindStringSubmatch(output)
		if len(m) != 2 {
			return 0, errors.New("could not parse average latency from windows ping output")
		}
		v, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return v, nil
	}

	// Linux/macOS summary line examples:
	// rtt min/avg/max/mdev = 10.123/20.456/30.789/1.234 ms
	// round-trip min/avg/max/stddev = 10.123/20.456/30.789/1.234 ms
	re := regexp.MustCompile(`(?m)^(?:rtt|round-trip)[^=]*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)(?:/[0-9.]+)?\s*ms`)
	m := re.FindStringSubmatch(output)
	if len(m) < 3 {
		return 0, errors.New("could not parse average latency from ping output")
	}
	avgStr := m[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency %q: %w", avgStr, err)
	}
	return avg, nil
}

func main() {
	host := flag.String("host", "8.8.8.8", "Host to ping (IP or DNS name)")
	count := flag.Int("count", 4, "Number of ping attempts")
	flag.Parse()

	avg, err := MeasureLatency(*host, *count)
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error:", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s over %d ping(s): %.3f ms\n", *host, *count, avg)
}

