package main

import (
	"bytes"
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build OS-specific ping args without invoking a shell (avoids injection issues).
	var args []string
	switch runtime.GOOS {
	case "windows":
		// Windows: -n count
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		// Linux/macOS: -c count
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	if err != nil {
		// ping may return non-zero even when it prints useful stats; still try to parse.
		avg, parseErr := parsePingAverage(output)
		if parseErr == nil {
			return avg, nil
		}
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
	}

	avg, err := parsePingAverage(output)
	if err != nil {
		return 0, err
	}
	return avg, nil
}

func parsePingAverage(output []byte) (float64, error) {
	s := string(bytes.TrimSpace(output))
	if s == "" {
		return 0, errors.New("empty ping output")
	}

	// Linux: "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
	// macOS: "round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms"
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms\s*$`)
	if m := reUnix.FindStringSubmatch(s); len(m) == 2 {
		return strconv.ParseFloat(m[1], 64)
	}

	// Windows: "Average = 23ms" (locale may vary, but this is the common English output)
	reWin := regexp.MustCompile(`(?mi)\bAverage\s*=\s*(\d+)\s*ms\b`)
	if m := reWin.FindStringSubmatch(s); len(m) == 2 {
		v, err := strconv.Atoi(m[1])
		if err != nil {
			return 0, fmt.Errorf("failed to parse windows average latency: %w", err)
		}
		return float64(v), nil
	}

	return 0, errors.New("could not find average latency in ping output")
}

func main() {
	// Example usage:
	// avg, err := MeasureLatency("8.8.8.8", 4)
	// fmt.Println(avg, err)
}

