package main

import (
	"bytes"
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
	"time"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
//
// Security notes:
// - Avoids shell execution (no "bash -c") to prevent command injection.
// - Validates host to a conservative allowlist (hostname/IPv4/IPv6 literal characters).
// - Clamps count to a reasonable maximum to reduce abuse/DoS.
// - Uses a timeout to avoid hanging processes.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	// Limit count to reduce resource abuse.
	if count > 20 {
		count = 20
	}

	// Conservative host validation: allow typical hostname chars and IPv4/IPv6 literals.
	// This blocks spaces and shell metacharacters even though we don't use a shell.
	// Allowed: letters, digits, dot, hyphen, colon, brackets (for IPv6 like [::1]).
	hostRe := regexp.MustCompile(`^[a-zA-Z0-9.\-:\[\]]+$`)
	if !hostRe.MatchString(host) {
		return 0, fmt.Errorf("invalid host: %q", host)
	}

	// Execute ping without a shell to prevent injection.
	// Linux/macOS: ping -c <count> <host>
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	// Timeout: roughly 2s per ping + small overhead.
	timeout := time.Duration(count*2+2) * time.Second
	var stdoutStderr bytes.Buffer
	cmd.Stdout = &stdoutStderr
	cmd.Stderr = &stdoutStderr

	if err := cmd.Start(); err != nil {
		return 0, fmt.Errorf("failed to start ping: %w", err)
	}

	done := make(chan error, 1)
	go func() { done <- cmd.Wait() }()

	select {
	case err := <-done:
		out := stdoutStderr.String()
		if err != nil {
			return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, out)
		}
		return parsePingAverage(out)
	case <-time.After(timeout):
		_ = cmd.Process.Kill()
		_ = cmd.Wait()
		return 0, fmt.Errorf("ping timed out after %s", timeout)
	}
}

func parsePingAverage(output string) (float64, error) {
	// Common Linux format:
	// rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// Some variants:
	// round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`(?m)^(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms\s*$`)
	m := re.FindStringSubmatch(output)
	if len(m) < 2 {
		return 0, errors.New("could not parse average latency from ping output")
	}

	avg, err := strconv.ParseFloat(m[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}
	return avg, nil
}

func main() {
	// Intentionally left empty. This file provides the MeasureLatency utility function.
}

