// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
//
// Notes:
// - Uses exec.Command directly (no shell) to avoid injection issues.
// - Supports common Linux/macOS ping summary formats:
//   - Linux: "rtt min/avg/max/mdev = ... ms"
//   - macOS: "round-trip min/avg/max/stddev = ... ms"
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Prefer direct exec without shell.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	var combined bytes.Buffer
	cmd.Stdout = &combined
	cmd.Stderr = &combined

	err := cmd.Run()
	outStr := combined.String()
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, outStr)
	}

	avg, perr := parsePingAverage(outStr)
	if perr != nil {
		return 0, fmt.Errorf("failed to parse ping output: %w (output: %s)", perr, outStr)
	}
	return avg, nil
}

func parsePingAverage(output string) (float64, error) {
	// Linux example:
	// rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	linuxRe := regexp.MustCompile(`(?m)^rtt min/avg/max/(?:mdev|stddev) = [0-9.]+/([0-9.]+)/[0-9.]+/[0-9.]+ ms$`)

	// macOS example:
	// round-trip min/avg/max/stddev = 13.833/13.833/13.833/0.000 ms
	macRe := regexp.MustCompile(`(?m)^round-trip min/avg/max/stddev = [0-9.]+/([0-9.]+)/[0-9.]+/[0-9.]+ ms$`)

	for _, re := range []*regexp.Regexp{linuxRe, macRe} {
		m := re.FindStringSubmatch(output)
		if len(m) == 2 {
			avg, err := strconv.ParseFloat(m[1], 64)
			if err != nil {
				return 0, fmt.Errorf("invalid avg latency %q: %w", m[1], err)
			}
			return avg, nil
		}
	}

	return 0, errors.New("could not find RTT statistics line")
}

