package main

import (
	"bytes"
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
	"time"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
//
// Security notes:
// - Avoids shell execution ("bash -c") to prevent command injection.
// - Validates host input to a conservative allowlist.
// - Uses a timeout to avoid hanging processes.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	if count > 20 {
		return 0, errors.New("count too large (max 20)")
	}

	// Conservative validation: allow typical DNS names, IPv4, IPv6 literals.
	// Disallow whitespace and shell metacharacters by allowlisting.
	// Note: This does not guarantee resolvability; it only reduces injection risk.
	if !isSafeHost(host) {
		return 0, fmt.Errorf("invalid host: %q", host)
	}

	// Use exec.Command directly (no shell).
	// Linux/macOS: ping -c <count> <host>
	// (Windows uses different flags; not handled here.)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	// Ensure ping doesn't hang indefinitely (e.g., no route, DNS issues).
	// Rough bound: per-ping timeout + overhead.
	cmdTimeout := time.Duration(count)*2*time.Second + 2*time.Second
	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	if err := runWithTimeout(cmd, cmdTimeout); err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, out.String())
	}

	avg, err := parsePingAverage(out.String())
	if err != nil {
		return 0, err
	}
	return avg, nil
}

func runWithTimeout(cmd *exec.Cmd, timeout time.Duration) error {
	if err := cmd.Start(); err != nil {
		return err
	}

	done := make(chan error, 1)
	go func() { done <- cmd.Wait() }()

	select {
	case err := <-done:
		return err
	case <-time.After(timeout):
		_ = cmd.Process.Kill()
		<-done // wait for Wait() to return after kill
		return fmt.Errorf("ping timed out after %s", timeout)
	}
}

func isSafeHost(host string) bool {
	// Allow:
	// - DNS labels: letters/digits/hyphen/dot (no leading/trailing dot enforced here)
	// - IPv4: digits and dots
	// - IPv6 literal: hex digits, colon, and optional zone id (%eth0) on some systems
	//
	// Disallow any whitespace and other punctuation.
	re := regexp.MustCompile(`\A[0-9A-Za-z.\-:%]+\z`)
	if !re.MatchString(host) {
		return false
	}
	// Prevent obviously dangerous edge cases like starting with '-' (could be interpreted as option).
	if strings.HasPrefix(host, "-") {
		return false
	}
	return true
}

func parsePingAverage(output string) (float64, error) {
	// Linux: "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
	// macOS: "round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms"
	re := regexp.MustCompile(`(?m)^(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms\s*$`)
	m := re.FindStringSubmatch(output)
	if len(m) < 2 {
		return 0, errors.New("could not find/parse RTT statistics in ping output")
	}

	avg, err := strconv.ParseFloat(m[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}
	return avg, nil
}

