// Supports:
// - Linux: "rtt min/avg/max/mdev = 10.123/20.456/30.789/1.234 ms"
// - macOS: "round-trip min/avg/max/stddev = 10.123/20.456/30.789/1.234 ms"
// - Windows: "Average = 23ms" (or localized variants may not match)
func parsePingAverage(out string) (float64, error) {
	// Linux/macOS style
