	}
	return avg, nil
}

// parsePingAverage extracts average latency (ms) from typical ping output.
// Supports:
// - Linux/macOS: "rtt min/avg/max/mdev = 10.123/20.456/30.789/..." or "round-trip min/avg/max/stddev = ..."
// - Windows: "Average = 23ms" (localized output may vary; this targets common English output)
func parsePingAverage(output string) (float64, error) {
	// Unix-like: rtt min/avg/max/mdev = 10.123/20.456/...
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)[^=]*=\s*([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)/`)
	if m := reUnix.FindStringSubmatch(output); len(m) == 4 {
		avg, err := strconv.ParseFloat(m[2], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse unix avg latency: %w", err)
		}
		return avg, nil
	}

	// Windows: Average = 23ms (sometimes "Average = 23ms," etc.)
	reWin := regexp.MustCompile(`(?mi)\bAverage\s*=\s*([0-9]+)\s*ms\b`)
	if m := reWin.FindStringSubmatch(output); len(m) == 2 {
		avgInt, err := strconv.Atoi(m[1])
		if err != nil {
			return 0, fmt.Errorf("failed to parse windows avg latency: %w", err)
		}
		return float64(avgInt), nil
	}

	// Fallback: try to compute average from per-packet "time=XX ms" occurrences.
	// Common patterns: "time=12.3 ms", "time<1ms", "time=12ms"
	reTime := regexp.MustCompile(`(?i)\btime[=<]\s*([0-9]+(?:\.[0-9]+)?)\s*ms\b`)
	matches := reTime.FindAllStringSubmatch(output, -1)
	if len(matches) > 0 {
		var sum float64
		var n int
		for _, m := range matches {
			if len(m) < 2 {
				continue
			}
			v, err := strconv.ParseFloat(m[1], 64)
			if err != nil {
				continue
			}
			sum += v
			n++
		}
		if n > 0 {
			return sum / float64(n), nil
		}
	}

	return 0, errors.New("could not parse average latency from ping output")
}

func main() {
	// Simple CLI usage:
	//   go run . <host> [count]
	// Examples:
	//   go run . 8.8.8.8 5
	//   go run . google.com
	if len(os.Args) < 2 {
