package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build args without invoking a shell to avoid injection issues.
	var args []string
	switch runtime.GOOS {
	case "windows":
		// Windows: -n count. (Timeout/size left default.)
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		// Linux/macOS: -c count.
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	outStr := string(output)
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, outStr)
	}

	avg, parseErr := parsePingAverage(outStr)
	if parseErr != nil {
		return 0, parseErr
	}
	return avg, nil
}

func parsePingAverage(output string) (float64, error) {
	// Linux: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)[^=]*=\s*([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)\s*ms`)
	if m := reUnix.FindStringSubmatch(output); len(m) >= 3 {
		avg, err := strconv.ParseFloat(m[2], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
		}
		return avg, nil
	}

	// Windows (English): Approximate round trip times in milli-seconds:
	// Minimum = 12ms, Maximum = 34ms, Average = 23ms
	reWin := regexp.MustCompile(`(?mi)Average\s*=\s*([0-9]+)\s*ms`)
	if m := reWin.FindStringSubmatch(output); len(m) >= 2 {
		avg, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
		}
		return avg, nil
	}

	return 0, errors.New("could not find average latency in ping output")
}

func main() {
	// Intentionally empty. Use MeasureLatency from your application/tests.
}

