package main

import (
	"bytes"
	"context"
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
	"time"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
//
// Security notes:
// - Avoids shell execution (no "bash -c") to prevent command injection.
// - Validates host and count.
// - Uses a timeout to avoid hanging indefinitely.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if strings.ContainsAny(host, " \t\r\n") {
		return 0, errors.New("host must not contain whitespace")
	}
	// Conservative validation: allow typical DNS names, IPv4, IPv6 literals (with ':'),
	// and bracketed IPv6. Disallow shell metacharacters and other unsafe characters.
	// This is not a full RFC validator; it is a safety filter.
	hostRe := regexp.MustCompile(`^\[?[a-zA-Z0-9][a-zA-Z0-9.\-:]*\]?$`)
	if !hostRe.MatchString(host) {
		return 0, errors.New("invalid host format")
	}

	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	if count > 20 {
		return 0, errors.New("count too large (max 20)")
	}

	// Prevent indefinite hang.
	// Rough budget: ~2s per ping + overhead.
	timeout := time.Duration(count*2+2) * time.Second
	ctx, cancel := context.WithTimeout(context.Background(), timeout)
	defer cancel()

	// Use exec.CommandContext directly (no shell).
	// Linux/macOS: ping -c <count> <host>
	cmd := exec.CommandContext(ctx, "ping", "-c", strconv.Itoa(count), host)

	output, err := cmd.CombinedOutput()
	if ctx.Err() == context.DeadlineExceeded {
		out := string(bytes.TrimSpace(output))
		if len(out) > 4096 {
			out = out[:4096] + "...(truncated)"
		}
		return 0, fmt.Errorf("ping timed out after %s (output: %s)", timeout, out)
	}
	if err != nil {
		// Include output for debugging, but trim to a reasonable size.
		out := string(bytes.TrimSpace(output))
		if len(out) > 4096 {
			out = out[:4096] + "...(truncated)"
		}
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, out)
	}

	avg, parseErr := parsePingAverage(string(output))
	if parseErr != nil {
		return 0, parseErr
	}
	return avg, nil
}

func parsePingAverage(output string) (float64, error) {
	// Support common ping formats:
	// Linux: "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
	// BusyBox: "round-trip min/avg/max = 12.345/23.456/34.567 ms"
	// macOS: "round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms"
	lines := strings.Split(output, "\n")
	var statsLine string
	for _, line := range lines {
		l := strings.TrimSpace(line)
		if strings.Contains(l, "min/avg/max") && strings.Contains(l, "=") {
			statsLine = l
			break
		}
	}
	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Extract the avg value (second number) from the slash-separated stats after '='.
	// Example: "... = 12.345/23.456/34.567/5.678 ms"
	re := regexp.MustCompile(`=\s*([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)(?:/([0-9]+(?:\.[0-9]+)?))?\s*ms`)
	m := re.FindStringSubmatch(statsLine)
	if len(m) < 3 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := m[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}
