func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host must not be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be > 0")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux/macOS: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var errBuf bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errBuf

	if err := cmd.Run(); err != nil {
		combined := strings.TrimSpace(out.String() + "\n" + errBuf.String())
		if combined == "" {
			combined = err.Error()
		}
		return 0, fmt.Errorf("ping failed: %s", combined)
	}

	output := out.String()

	// Linux/macOS: rtt min/avg/max/mdev = 10.123/20.456/30.789/...
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)[^=]*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s*ms`)
	if m := reUnix.FindStringSubmatch(output); len(m) == 5 {
		avg, err := strconv.ParseFloat(m[2], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse avg latency: %w", err)
		}
		return avg, nil
	}

	// Windows: Average = 23ms (English locale)
	reWin := regexp.MustCompile(`(?mi)Average\s*=\s*([0-9]+)\s*ms`)
	if m := reWin.FindStringSubmatch(output); len(m) == 2 {
		avgMs, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse avg latency: %w", err)
		}
		return avgMs, nil
	}

	// Fallback: compute average from individual "time=" occurrences.
	// Examples:
	//   time=23.4 ms
	//   time<1ms (Windows) -> treat as 1ms for averaging.
	reTime := regexp.MustCompile(`(?i)time[=<]\s*([0-9.]+)\s*ms|time[=<]\s*<\s*1\s*ms|time[=<]\s*<\s*1ms`)
	matches := reTime.FindAllStringSubmatch(output, -1)
	if len(matches) == 0 {
		return 0, fmt.Errorf("could not parse latency from ping output:\n%s", output)
	}

	var sum float64
	var n int
	for _, sm := range matches {
		// sm[1] may be empty for the <1ms variants
		if len(sm) > 1 && sm[1] != "" {
			v, err := strconv.ParseFloat(sm[1], 64)
			if err != nil {
				continue
			}
			sum += v
			n++
		} else {
			// time<1ms
			sum += 1.0
			n++
		}
	}
	if n == 0 {
		return 0, fmt.Errorf("could not parse any numeric latency values from ping output:\n%s", output)
	}
	return sum / float64(n), nil
}

func main() {
	host := flag.String("host", "8.8.8.8", "target host to ping (IP or hostname)")
	count := flag.Int("count", 4, "number of ping attempts")
	flag.Parse()

	avg, err := MeasureLatency(*host, *count)
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error:", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.3f ms\n", *host, *count, avg)
}

