	reTimes := regexp.MustCompile(`(?i)\btime[=<]\s*([0-9.]+)\s*ms\b|\btime=\s*([0-9.]+)\s*ms\b|\btime=\s*([0-9.]+)\s*ms\b|\btime=\s*([0-9.]+)\s*ms\b`)
