	re := regexp.MustCompile(`(?i)\btime\s*[=<]\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b`)
	// And "time=12ms" without space:
	reNoSpace := regexp.MustCompile(`(?i)\btime\s*[=<]\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b|\btime\s*=\s*([0-9.]+)\s*ms\b`)
