// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build arguments without invoking a shell to avoid injection issues.
	args := pingArgs(host, count)

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	outStr := string(output)
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, strings.TrimSpace(outStr))
	}

	avg, parseErr := parsePingAverage(outStr)
	if parseErr != nil {
		return 0, fmt.Errorf("could not parse ping output: %w (output: %s)", parseErr, strings.TrimSpace(outStr))
	}
	return avg, nil
}

func pingArgs(host string, count int) []string {
	// Linux: ping -c <count> <host>
	// macOS: ping -c <count> <host>
	// Windows: ping -n <count> <host>
	if runtime.GOOS == "windows" {
		return []string{"-n", strconv.Itoa(count), host}
	}
	return []string{"-c", strconv.Itoa(count), host}
}

func parsePingAverage(output string) (float64, error) {
	// Linux example:
	// rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	//
	// macOS example:
	// round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	//
	// Some systems might omit decimals (e.g., 12/23/34/5 ms), so accept integers too.
	re := regexp.MustCompile(`(?m)^(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)/([0-9]+(?:\.[0-9]+)?)\s*ms\s*$`)
	m := re.FindStringSubmatch(output)
	if len(m) < 3 {
		// Fallback: search line-by-line in case of extra prefixes.
		for _, line := range strings.Split(output, "\n") {
			line = strings.TrimSpace(line)
			if line == "" {
				continue
			}
			m = re.FindStringSubmatch(line)
			if len(m) >= 3 {
				break
			}
		}
	}
	if len(m) < 3 {
		return 0, errors.New("RTT statistics line not found")
	}

	avgStr := m[2]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("invalid average latency %q: %w", avgStr, err)
	}
	return avg, nil
}

