package main

import (
	"bytes"
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
//
// Security fixes:
// - Avoids shell execution ("bash -c") to prevent command injection.
// - Validates host input to a safe character set and length.
// - Bounds count to a reasonable maximum to avoid resource exhaustion.
// - Uses exec.Command with arguments (no shell).
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if len(host) > 253 {
		return 0, errors.New("host is too long")
	}

	// Allow common hostname/IP formats (domain labels, IPv4, IPv6 literals without brackets).
	// Disallow whitespace and shell metacharacters by only allowing a restricted charset.
	hostRe := regexp.MustCompile(`^[a-zA-Z0-9.\-:]+$`)
	if !hostRe.MatchString(host) {
		return 0, errors.New("host contains invalid characters")
	}

	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	const maxCount = 20
	if count > maxCount {
		return 0, fmt.Errorf("count too large (max %d)", maxCount)
	}

	// Execute ping without invoking a shell.
	// Linux/macOS: -c <count>
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, out.String())
	}

	outputStr := out.String()

	// Parse average RTT from typical ping outputs:
	// Linux: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`(?m)^(?:rtt|round-trip) [^=]*= ([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+) ms`)
	m := re.FindStringSubmatch(outputStr)
	if len(m) < 3 {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	avg, err := strconv.ParseFloat(m[2], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Intentionally left minimal. MeasureLatency is the utility function.
}

