package main

import (
	"bytes"
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the given host "count" times and returns the average latency in milliseconds.
// It executes the system "ping" command via os/exec and parses its output.
//
// Notes:
// - On Windows it uses: ping -n <count> <host>
// - On Unix-like systems it uses: ping -c <count> <host>
// - Requires the "ping" command to be available in PATH.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be > 0")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var errBuf bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errBuf

	err := cmd.Run()
	output := out.String()
	stderr := strings.TrimSpace(errBuf.String())

	// Even if ping exits non-zero (packet loss), it may still print usable stats.
	avg, parseErr := parsePingAverage(output)
	if parseErr == nil && avg > 0 {
		return avg, nil
	}

	// If parsing failed and command errored, surface that.
	if err != nil {
		if stderr != "" {
			return 0, fmt.Errorf("ping failed: %w: %s", err, stderr)
		}
		return 0, fmt.Errorf("ping failed: %w", err)
	}

	// Command succeeded but parsing failed.
	if stderr != "" {
		return 0, fmt.Errorf("failed to parse ping output: %v (stderr: %s)", parseErr, stderr)
	}
	return 0, fmt.Errorf("failed to parse ping output: %v", parseErr)
}

func parsePingAverage(output string) (float64, error) {
	// Linux/macOS style:
	//   rtt min/avg/max/mdev = 10.123/20.456/30.789/1.234 ms
	//   round-trip min/avg/max/stddev = 10.123/20.456/30.789/1.234 ms
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)[^=]*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s*ms`)
	if m := reUnix.FindStringSubmatch(output); len(m) == 5 {
		avgStr := m[2]
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("parse avg latency %q: %w", avgStr, err)
		}
		return avg, nil
	}

	// Windows style:
	//   Average = 23ms
	reWin := regexp.MustCompile(`(?mi)Average\s*=\s*(\d+)\s*ms`)
	if m := reWin.FindStringSubmatch(output); len(m) == 2 {
		avgStr := m[1]
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("parse avg latency %q: %w", avgStr, err)
		}
		return avg, nil
	}

	return 0, errors.New("no average latency found in ping output")
}

func main() {
	// Minimal CLI usage:
	//   go run . <host> <count>
	// Example:
	//   go run . google.com 5
	if len(os.Args) < 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(2)
	}

	host := os.Args[1]
	count, err := strconv.Atoi(os.Args[2])
	if err != nil {
		fmt.Fprintf(os.Stderr, "Invalid count: %v\n", err)
		os.Exit(2)
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.3f ms\n", host, count, avg)
}

