	}
	return avg, nil
}

func parseAverageLatency(output string) (float64, error) {
	s := output

	// Linux/macOS style:
	// rtt min/avg/max/mdev = 11.123/22.456/33.789/1.234 ms
	// round-trip min/avg/max/stddev = 11.123/22.456/33.789/1.234 ms
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)[^=]*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s*ms\s*$`)
	if m := reUnix.FindStringSubmatch(s); m != nil {
		avgStr := m[2]
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("invalid avg value %q: %w", avgStr, err)
		}
		return avg, nil
	}

	// Windows style:
	// Approximate round trip times in milli-seconds:
	// Minimum = 1ms, Maximum = 3ms, Average = 2ms
	reWin := regexp.MustCompile(`(?mi)Average\s*=\s*([0-9]+)\s*ms`)
	if m := reWin.FindStringSubmatch(s); m != nil {
