package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Avoid shell invocation to prevent injection and quoting issues.
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		// Windows ping uses: -n <count>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux/macOS typically use: -c <count>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	outStr := string(output)
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, outStr)
	}

	avg, perr := parseAverageLatencyMs(outStr)
	if perr != nil {
		return 0, fmt.Errorf("could not parse average latency: %w (output: %s)", perr, outStr)
	}
	return avg, nil
}

func parseAverageLatencyMs(out string) (float64, error) {
	// Linux: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s*ms\s*$`)
	if m := reUnix.FindStringSubmatch(out); len(m) == 5 {
		avg, err := strconv.ParseFloat(m[2], 64)
		if err != nil {
			return 0, fmt.Errorf("invalid avg value %q: %w", m[2], err)
		}
		return avg, nil
	}

	// Windows: Average = 23ms (localized systems may differ; this covers common English output)
	reWin := regexp.MustCompile(`(?mi)^\s*Average\s*=\s*([0-9]+)\s*ms\s*$`)
	if m := reWin.FindStringSubmatch(out); len(m) == 2 {
		avg, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			return 0, fmt.Errorf("invalid avg value %q: %w", m[1], err)
		}
		return avg, nil
	}

	return 0, errors.New("RTT statistics not found")
}

func main() {
	// Example usage:
	// avg, err := MeasureLatency("8.8.8.8", 3)
	// fmt.Println(avg, err)
}

