	// This is not a full RFC validator; it is an injection hardening measure.
	// Allows: letters, digits, dot, dash, colon (IPv6), brackets (IPv6 literal), underscore.
	hostRe := regexp.MustCompile(`^[a-zA-Z0-9.\-:\[\]_]+$`)
