// MeasureLatency pings the given host 'count' times and returns the average latency in milliseconds.
// It executes the system 'ping' command via os/exec and parses its output.
// Works on common ping implementations on Linux/macOS and Windows.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host must not be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be > 0")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows: ping -n <count> <host>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux/macOS: ping -c <count> <host>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var errBuf bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errBuf

	if err := cmd.Run(); err != nil {
		msg := strings.TrimSpace(errBuf.String())
		if msg == "" {
			msg = strings.TrimSpace(out.String())
		}
		if msg == "" {
			msg = err.Error()
		}
		return 0, fmt.Errorf("ping failed: %s", msg)
	}

	avg, ok := parseAverageLatencyMs(out.String())
	if !ok {
		return 0, fmt.Errorf("could not parse average latency from ping output:\n%s", out.String())
	}
	return avg, nil
}

// parseAverageLatencyMs extracts the average latency in ms from ping output.
// Supports typical outputs:
// - Linux: "rtt min/avg/max/mdev = 10.123/20.456/30.789/1.234 ms"
// - macOS: "round-trip min/avg/max/stddev = 10.123/20.456/30.789/1.234 ms"
// - Windows: "Average = 23ms" (English) and some localized variants like "Average = 23ms" may differ.
// Also handles Windows "Average = 23ms" with optional space.
func parseAverageLatencyMs(output string) (float64, bool) {
	// Unix-like: ... = min/avg/max/... ms
	unixRe := regexp.MustCompile(`(?m)^(?:rtt|round-trip).*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s*ms\s*$`)
	if m := unixRe.FindStringSubmatch(output); len(m) == 5 {
		avg, err := strconv.ParseFloat(m[2], 64)
		if err == nil {
			return avg, true
		}
	}

	// Some ping variants might omit the leading keyword; try a looser match near the end.
	looseUnixRe := regexp.MustCompile(`(?m)=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s*ms\s*$`)
	if m := looseUnixRe.FindStringSubmatch(output); len(m) == 5 {
		avg, err := strconv.ParseFloat(m[2], 64)
		if err == nil {
			return avg, true
		}
	}

	// Windows: "Average = 23ms" (commonly English). We'll match case-insensitively.
	winRe := regexp.MustCompile(`(?mi)\bAverage\s*=\s*([0-9]+)\s*ms\b`)
	if m := winRe.FindStringSubmatch(output); len(m) == 2 {
		avgInt, err := strconv.Atoi(m[1])
		if err == nil {
			return float64(avgInt), true
		}
	}

	return 0, false
}

func main() {
	// Simple CLI usage:
	//   go run . <host> [count]
	// Examples:
	//   go run . 8.8.8.8 5
	//   go run . google.com
	if len(os.Args) < 2 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> [count]\n", os.Args[0])
		os.Exit(2)
	}

	host := os.Args[1]
	count := 4
	if len(os.Args) >= 3 {
		n, err := strconv.Atoi(os.Args[2])
		if err != nil || n <= 0 {
			fmt.Fprintln(os.Stderr, "count must be a positive integer")
			os.Exit(2)
		}
		count = n
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error:", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.3f ms\n", host, count, avg)
}

