	"strconv"
	"strings"
)

// MeasureLatency pings the given host `count` times and returns the average latency in milliseconds.
// It shells out to the system `ping` command via os/exec and parses its output.
//
// Notes:
// - On Linux/macOS it uses: ping -c <count> <host>
// - On Windows it uses: ping -n <count> <host>
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host must not be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be > 0")
	}

	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	var out bytes.Buffer
	var errBuf bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errBuf

	if err := cmd.Run(); err != nil {
		msg := strings.TrimSpace(errBuf.String())
		if msg == "" {
			msg = strings.TrimSpace(out.String())
		}
		if msg == "" {
			msg = err.Error()
		}
		return 0, fmt.Errorf("ping failed: %s", msg)
	}

	output := out.String()

	// Linux/macOS summary examples:
	//   rtt min/avg/max/mdev = 10.123/12.345/20.456/1.234 ms
	//   round-trip min/avg/max/stddev = 10.123/12.345/20.456/1.234 ms
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip).*= ([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+) ms$`)
	if m := reUnix.FindStringSubmatch(output); len(m) == 5 {
		avg, err := strconv.ParseFloat(m[2], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse avg latency: %w", err)
		}
		return avg, nil
	}

	// Windows summary example:
	//   Average = 12ms
	reWin := regexp.MustCompile(`(?mi)^\s*Average\s*=\s*([0-9]+)\s*ms\s*$`)
	if m := reWin.FindStringSubmatch(output); len(m) == 2 {
		avg, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse avg latency: %w", err)
		}
		return avg, nil
	}

	// Fallback: parse per-packet times and average them.
	// Examples:
	//   time=12.3 ms
	//   time<1ms
	reTime := regexp.MustCompile(`(?i)time[=<]\s*([0-9.]+)\s*ms`)
	matches := reTime.FindAllStringSubmatch(output, -1)
	if len(matches) == 0 {
		return 0, fmt.Errorf("could not parse ping output for average latency; raw output:\n%s", output)
	}

	var sum float64
	var n int
	for _, m := range matches {
		if len(m) != 2 {
			continue
		}
		v, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			continue
		}
		sum += v
		n++
	}
	if n == 0 {
		return 0, fmt.Errorf("could not parse any latency samples; raw output:\n%s", output)
	}
	return sum / float64(n), nil
}

func main() {
	host := flag.String("host", "8.8.8.8", "target host to ping (IP or DNS name)")
	count := flag.Int("count", 4, "number of ping attempts")
	flag.Parse()

	avg, err := MeasureLatency(*host, *count)
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error:", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d ping(s): %.3f ms\n", *host, *count, avg)
}

