package main

import (
	"bytes"
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
	"time"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
//
// Security notes:
// - Avoids shell execution ("bash -c") to prevent command injection.
// - Validates host input to reduce abuse (e.g., option injection).
// - Adds a timeout to prevent hanging processes.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	// Prevent resource abuse
	if count > 100 {
		return 0, errors.New("count too large (max 100)")
	}

	// Basic allowlist: hostname, IPv4, IPv6 (incl. zone), no spaces, no leading '-'
	// This is not a DNS validator; it is an input hardening measure.
	if strings.HasPrefix(host, "-") {
		return 0, errors.New("invalid host")
	}
	hostRe := regexp.MustCompile(`^[A-Za-z0-9.\-_:]+$`)
	if !hostRe.MatchString(host) {
		return 0, errors.New("invalid host")
	}

	// Use exec.Command directly (no shell), so arguments are not interpreted.
	// ping is typically setuid/cap_net_raw or requires privileges depending on OS config.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	// Timeout: be conservative; ping default interval is ~1s, plus some slack.
	// Also prevents hanging if name resolution or command stalls.
	cmdTimeout := time.Duration(count+3) * time.Second
	if cmdTimeout < 5*time.Second {
		cmdTimeout = 5 * time.Second
	}
	timer := time.AfterFunc(cmdTimeout, func() {
		_ = cmd.Process.Kill()
	})
	defer timer.Stop()

	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, out.String())
	}

	outputStr := out.String()

	// Linux typically: "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
	// macOS/BSD typically: "round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms"
	re := regexp.MustCompile(`(?m)^(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms\s*$`)
	matches := re.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		return 0, errors.New("could not parse average latency from ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Intentionally left minimal; MeasureLatency is the utility function.
}

