package main

import (
	"bytes"
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the given host count times and returns the average latency in milliseconds.
// It executes the system "ping" command via os/exec and parses its output.
//
// Notes:
// - On Windows it uses: ping -n <count> <host>
// - On Unix-like systems it uses: ping -c <count> <host>
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host must not be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be > 0")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var errOut bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errOut

	if err := cmd.Run(); err != nil {
		msg := strings.TrimSpace(errOut.String())
		if msg == "" {
			msg = strings.TrimSpace(out.String())
		}
		if msg == "" {
			msg = err.Error()
		}
		return 0, fmt.Errorf("ping failed: %s", msg)
	}

	output := out.String()

	// Try to parse average latency from summary lines:
	// Linux/macOS: "rtt min/avg/max/mdev = 10.123/20.456/30.789/1.234 ms"
	// BusyBox:     "round-trip min/avg/max = 10.123/20.456/30.789 ms"
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)[^=]*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)(?:/([0-9.]+))?\s*ms`)
	if m := reUnix.FindStringSubmatch(output); len(m) >= 3 {
		avg, err := strconv.ParseFloat(m[2], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Windows: "Average = 23ms" (English locales). Some locales differ.
	reWin := regexp.MustCompile(`(?mi)\bAverage\s*=\s*([0-9]+)\s*ms\b`)
	if m := reWin.FindStringSubmatch(output); len(m) == 2 {
		avg, err := strconv.ParseFloat(m[1], 64)
		if err == nil {
			return avg, nil
		}
	}

	// Fallback: compute average from per-packet "time=" occurrences.
	// Common patterns:
	// - "time=23.4 ms"
	// - "time<1ms" (Windows)
	reTime := regexp.MustCompile(`(?i)\btime[=<]\s*([0-9]+(?:\.[0-9]+)?)\s*ms\b`)
	matches := reTime.FindAllStringSubmatch(output, -1)
	if len(matches) == 0 {
		// Handle "time<1ms" without a space: "time<1ms"
		reTimeNoSpace := regexp.MustCompile(`(?i)\btime[=<]\s*([0-9]+(?:\.[0-9]+)?)\s*ms\b|\btime[=<]\s*([0-9]+(?:\.[0-9]+)?)ms\b`)
		matches = reTimeNoSpace.FindAllStringSubmatch(output, -1)
	}

	var sum float64
	var n int
	for _, mm := range matches {
		val := ""
		for i := 1; i < len(mm); i++ {
			if mm[i] != "" {
				val = mm[i]
				break
			}
		}
		if val == "" {
			continue
		}
		f, err := strconv.ParseFloat(val, 64)
		if err != nil {
			continue
		}
		sum += f
		n++
	}
	if n > 0 {
		return sum / float64(n), nil
	}

	return 0, fmt.Errorf("unable to parse average latency from ping output")
}

func main() {
	// Simple CLI usage:
	//   go run . <host> [count]
	// Examples:
	//   go run . 8.8.8.8 5
	//   go run . google.com
	if len(os.Args) < 2 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> [count]\n", os.Args[0])
		os.Exit(2)
	}

	host := os.Args[1]
	count := 4
	if len(os.Args) >= 3 {
		c, err := strconv.Atoi(os.Args[2])
		if err != nil || c <= 0 {
			fmt.Fprintln(os.Stderr, "count must be a positive integer")
			os.Exit(2)
		}
		count = c
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error:", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.3f ms\n", host, count, avg)
}

