	}
	return avg, nil
}

func parsePingAverageMs(output string) (float64, error) {
	// Linux: rtt min/avg/max/mdev = 11.123/22.234/...
	// macOS: round-trip min/avg/max/stddev = 11.123/22.234/...
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)[^=]*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)(?:/([0-9.]+))?\s*ms\s*$`)
	if m := reUnix.FindStringSubmatch(output); m != nil {
		avgStr := m[2]
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency %q: %w", avgStr, err)
		}
		return avg, nil
	}

	// Windows: Average = 23ms (English) or localized variants.
	// Also sometimes: Average = 23ms, Minimum = ..., Maximum = ...
	reWin := regexp.MustCompile(`(?mi)\bAverage\s*=\s*([0-9]+)\s*ms\b`)
