package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Avoid shell invocation to prevent injection and quoting issues.
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows ping uses: -n count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Linux/macOS typically use: -c count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	outStr := string(output)
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, outStr)
	}

	avg, parseErr := parsePingAverage(outStr)
	if parseErr != nil {
		return 0, fmt.Errorf("could not parse average latency: %w (output: %s)", parseErr, outStr)
	}
	return avg, nil
}

func parsePingAverage(out string) (float64, error) {
	// Linux (iputils):
	// rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS:
	// round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	if m := reUnix.FindStringSubmatch(out); len(m) == 2 {
		return strconv.ParseFloat(m[1], 64)
	}

	// Windows:
	// Average = 23ms
	reWin := regexp.MustCompile(`(?mi)^\s*Average\s*=\s*(\d+)\s*ms\s*$`)
	if m := reWin.FindStringSubmatch(out); len(m) == 2 {
		v, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			return 0, err
		}
		return v, nil
	}

	return 0, errors.New("RTT statistics not found")
}

func main() {
	// Utility function implementation; no CLI required by the task.
}

