	}
	return avg, nil
}

func parsePingAverage(output []byte) (float64, error) {
	out := string(output)

	// Linux: "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
	linuxRe := regexp.MustCompile(`(?m)^(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s+=\s+[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s+ms\s*$`)
