	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the given host 'count' times and returns the average latency in milliseconds.
// It executes the system "ping" command via os/exec and parses its output.
// Note: output formats differ across OSes; this function supports common Linux/macOS/Windows formats.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host must not be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be > 0")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		// Windows: -n <count>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux/macOS: -c <count>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var errOut bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errOut

	if err := cmd.Run(); err != nil {
		msg := strings.TrimSpace(errOut.String())
		if msg == "" {
			msg = strings.TrimSpace(out.String())
		}
		if msg == "" {
			msg = err.Error()
		}
		return 0, fmt.Errorf("ping failed: %s", msg)
	}

	avg, ok := parsePingAverage(out.String())
	if !ok {
		return 0, fmt.Errorf("unable to parse average latency from ping output")
	}
	return avg, nil
}

func parsePingAverage(s string) (float64, bool) {
	// Linux: rtt min/avg/max/mdev = 10.123/20.456/30.789/1.234 ms
	// macOS: round-trip min/avg/max/stddev = 10.123/20.456/30.789/1.234 ms
	reUnix := regexp.MustCompile(`(?m)(?:rtt|round-trip)[^=]*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s*ms`)
	if m := reUnix.FindStringSubmatch(s); len(m) == 5 {
		v, err := strconv.ParseFloat(m[2], 64) // avg
		if err == nil {
			return v, true
		}
	}

	// Windows (English): Average = 23ms
	reWin := regexp.MustCompile(`(?mi)Average\s*=\s*([0-9]+)\s*ms`)
	if m := reWin.FindStringSubmatch(s); len(m) == 2 {
		v, err := strconv.ParseFloat(m[1], 64)
		if err == nil {
			return v, true
		}
	}

	// Fallback: compute average from per-packet "time=" lines.
	// Common:
	//  time=23.4 ms (Linux/macOS)
	//  time<1ms (Windows)
	//  time=1ms (Windows)
	reTime := regexp.MustCompile(`(?mi)\btime(?:=|<)\s*([0-9]+(?:\.[0-9]+)?)\s*ms`)
	matches := reTime.FindAllStringSubmatch(s, -1)
	if len(matches) == 0 {
		return 0, false
	}
	var sum float64
	var n int
	for _, m := range matches {
		if len(m) != 2 {
			continue
		}
		v, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			continue
		}
		sum += v
		n++
	}
	if n == 0 {
		return 0, false
	}
	return sum / float64(n), true
}

func main() {
	host := flag.String("host", "8.8.8.8", "target host to ping (IP or hostname)")
	count := flag.Int("count", 4, "number of ping attempts")
	flag.Parse()

	avg, err := MeasureLatency(*host, *count)
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error:", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s over %d ping(s): %.3f ms\n", *host, *count, avg)
}

