// MeasureLatency pings the given host count times and returns the average latency in milliseconds.
// It shells out to the system "ping" command via os/exec.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host is required")
	}
	if count <= 0 {
		return 0, errors.New("count must be > 0")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		// Windows: -n <count>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux/macOS/BSD: -c <count>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var errBuf bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errBuf

	if err := cmd.Run(); err != nil {
		msg := strings.TrimSpace(errBuf.String())
		if msg == "" {
			msg = strings.TrimSpace(out.String())
		}
		if msg == "" {
			msg = err.Error()
		}
		return 0, fmt.Errorf("ping failed: %s", msg)
	}

	avg, err := parsePingAverage(out.String())
	if err != nil {
		// include output to help diagnose parsing issues across platforms
		return 0, fmt.Errorf("failed to parse ping output: %w\n--- ping output ---\n%s", err, out.String())
	}
	return avg, nil
}

// parsePingAverage extracts average latency (ms) from common ping outputs.
// Supports typical Linux/macOS: "rtt min/avg/max/mdev = 10.1/20.2/30.3/1.2 ms"
// and Windows: "Average = 23ms" (English locale).
func parsePingAverage(output string) (float64, error) {
	// Linux/macOS/BSD style
	// Examples:
	// "rtt min/avg/max/mdev = 12.345/23.456/34.567/1.234 ms"
	// "round-trip min/avg/max/stddev = 10.1/20.2/30.3/1.2 ms"
	reUnix := regexp.MustCompile(`(?m)(?:rtt|round-trip)[^=]*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s*ms`)
	if m := reUnix.FindStringSubmatch(output); len(m) == 5 {
		avgStr := m[2]
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("invalid avg value %q: %w", avgStr, err)
		}
		return avg, nil
	}

	// Windows (English) style:
	// "Minimum = 1ms, Maximum = 4ms, Average = 2ms"
	reWin := regexp.MustCompile(`(?mi)Average\s*=\s*([0-9]+)\s*ms`)
	if m := reWin.FindStringSubmatch(output); len(m) == 2 {
		avgStr := m[1]
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("invalid avg value %q: %w", avgStr, err)
		}
		return avg, nil
	}

	return 0, errors.New("average latency not found in ping output")
}

func main() {
	host := flag.String("host", "", "Target host to ping (e.g. 8.8.8.8 or example.com)")
	count := flag.Int("count", 4, "Number of ping attempts")
	flag.Parse()

	if *host == "" {
		fmt.Fprintln(os.Stderr, "error: -host is required")
		flag.Usage()
		os.Exit(2)
	}

	avg, err := MeasureLatency(*host, *count)
	if err != nil {
		fmt.Fprintln(os.Stderr, err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.3f ms\n", *host, *count, avg)
}

