package main

import (
	"bytes"
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Avoid shell invocation to prevent injection and quoting issues.
	// Linux: ping -c <count> <host>
	// macOS/BSD: ping -c <count> <host> (RTT line format differs)
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)

	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, out.String())
	}

	outputStr := out.String()

	// Support common Linux and macOS/BSD summary formats:
	// Linux: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`(?m)^(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+)\s*ms\s*$`)
	matches := re.FindStringSubmatch(outputStr)
	if len(matches) < 3 {
		return 0, errors.New("could not find or parse RTT statistics in ping output")
	}

	avg, err := strconv.ParseFloat(matches[2], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

func main() {
	// Intentionally empty. This file provides the MeasureLatency utility function.
}

