// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	// Basic allowlist to reduce command/option injection and weird shell metacharacters.
	// Supports common hostnames, IPv4, IPv6 (including zone id), and trailing dot.
	// Note: we do NOT invoke a shell, but we still validate to avoid passing dangerous/invalid args to ping.
	const maxHostLen = 253
	if len(host) > maxHostLen {
		return 0, fmt.Errorf("host too long (max %d)", maxHostLen)
	}
	hostRe := regexp.MustCompile(`^[A-Za-z0-9.\-:_%\[\]]+$`)
	if !hostRe.MatchString(host) {
		return 0, errors.New("host contains invalid characters")
	}
	if strings.HasPrefix(host, "-") {
		return 0, errors.New("host must not start with '-'")
	}

	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	// Prevent abuse (very long runtimes).
	const maxCount = 20
	if count > maxCount {
		return 0, fmt.Errorf("count too large (max %d)", maxCount)
	}

	// Avoid shell execution to prevent command injection.
	// Use "--" to stop option parsing so host beginning with '-' can't be treated as a flag.
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), "--", host)

	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	if err := cmd.Run(); err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, out.String())
	}

	outputStr := out.String()

	// Linux example: rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS example: round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	re := regexp.MustCompile(`(?m)^(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms`)
	matches := re.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		return 0, errors.New("could not parse average latency from ping output")
	}

	avg, err := strconv.ParseFloat(matches[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}
	return avg, nil
}

