package main

import (
	"bytes"
	"errors"
	"flag"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the given host count times and returns the average latency in milliseconds.
// It uses the system "ping" command via os/exec and parses its output.
//
// Notes:
// - On Windows, it uses: ping -n <count> <host>
// - On Unix-like systems, it uses: ping -c <count> <host>
// - The average is derived from the summary line (avg on Unix, Average on Windows).
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host must not be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be > 0")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		// Windows ping: -n count
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		// Most Unix ping: -c count
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var errBuf bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errBuf

	err := cmd.Run()
	output := out.String()
	stderr := errBuf.String()

	// Even if ping returns non-zero (packet loss), it might still include stats.
	avg, parseErr := parseAverageLatency(output)
	if parseErr == nil {
		return avg, nil
	}

	// If parsing failed and command errored, surface useful info.
	if err != nil {
		msg := strings.TrimSpace(stderr)
		if msg == "" {
			msg = strings.TrimSpace(output)
		}
		if msg == "" {
			msg = err.Error()
		}
		return 0, fmt.Errorf("ping failed: %s", msg)
	}

	return 0, parseErr
}

func parseAverageLatency(pingOutput string) (float64, error) {
	// Unix-like summary examples:
	//   rtt min/avg/max/mdev = 12.345/23.456/34.567/1.234 ms
	//   round-trip min/avg/max/stddev = 12.345/23.456/34.567/1.234 ms
	unixRe := regexp.MustCompile(`(?m)^(?:rtt|round-trip)[^=]*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)/([0-9.]+)\s*ms\s*$`)
	if m := unixRe.FindStringSubmatch(pingOutput); len(m) == 5 {
		avgStr := m[2]
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse avg latency %q: %w", avgStr, err)
		}
		return avg, nil
	}

	// Windows summary example:
	//   Minimum = 1ms, Maximum = 2ms, Average = 1ms
	winRe := regexp.MustCompile(`(?mi)Average\s*=\s*([0-9]+)\s*ms`)
	if m := winRe.FindStringSubmatch(pingOutput); len(m) == 2 {
		avgStr := m[1]
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency %q: %w", avgStr, err)
		}
		return avg, nil
	}

	return 0, errors.New("could not parse average latency from ping output")
}

func main() {
	host := flag.String("host", "8.8.8.8", "target host to ping (IP or hostname)")
	count := flag.Int("count", 4, "number of ping attempts")
	flag.Parse()

	avg, err := MeasureLatency(*host, *count)
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error:", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.3f ms\n", *host, *count, avg)
}

