// - On Unix-like systems: uses "ping -c <count> <host>" and parses "avg" from the summary line.
// - Requires that "ping" is available on PATH and that the current user has permission to run it.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host must not be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be > 0")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var errBuf bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errBuf

	if err := cmd.Run(); err != nil {
		msg := strings.TrimSpace(errBuf.String())
		if msg == "" {
			msg = strings.TrimSpace(out.String())
		}
		if msg == "" {
			msg = err.Error()
		}
		return 0, fmt.Errorf("ping failed: %s", msg)
	}

	output := out.String()
	avg, err := parseAverageLatency(output)
	if err != nil {
		return 0, err
	}
	return avg, nil
}

func parseAverageLatency(pingOutput string) (float64, error) {
	if runtime.GOOS == "windows" {
		// Example:
		// Minimum = 1ms, Maximum = 4ms, Average = 2ms
		re := regexp.MustCompile(`(?i)Average\s*=\s*([0-9]+)\s*ms`)
		m := re.FindStringSubmatch(pingOutput)
		if len(m) != 2 {
			return 0, errors.New("unable to parse average latency from ping output (windows)")
		}
		v, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse average latency: %w", err)
		}
		return v, nil
	}

	// Unix-like summary examples:
	// rtt min/avg/max/mdev = 11.123/12.345/13.456/0.789 ms
	// round-trip min/avg/max/stddev = 11.123/12.345/13.456/0.789 ms
