package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build ping command without invoking a shell (avoid injection and quoting issues).
	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		// Windows ping: -n <count>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux/macOS ping: -c <count>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	output, err := cmd.CombinedOutput()
	outStr := string(output)
	if err != nil {
		return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, outStr)
	}

	// Parse average latency from common ping outputs:
	// Linux:  rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms
	// macOS:  round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms
	// BusyBox: round-trip min/avg/max = 12.345/23.456/34.567 ms
	reUnix := regexp.MustCompile(`(?m)(?:rtt|round-trip)\s+min/avg/max(?:/(?:mdev|stddev))?\s*=\s*[\d.]+/([\d.]+)/[\d.]+(?:/[\d.]+)?\s*ms`)
	if m := reUnix.FindStringSubmatch(outStr); len(m) >= 2 {
		avg, perr := strconv.ParseFloat(m[1], 64)
		if perr != nil {
			return 0, fmt.Errorf("failed to convert average latency to float: %w", perr)
		}
		return avg, nil
	}

	// Windows: Approximate round trip times in milli-seconds:
	//          Minimum = 10ms, Maximum = 12ms, Average = 11ms
	reWin := regexp.MustCompile(`(?mi)Average\s*=\s*(\d+)\s*ms`)
	if m := reWin.FindStringSubmatch(outStr); len(m) >= 2 {
		avg, perr := strconv.ParseFloat(m[1], 64)
		if perr != nil {
			return 0, fmt.Errorf("failed to convert average latency to float: %w", perr)
		}
		return avg, nil
	}

	return 0, errors.New("could not parse average latency from ping output")
}

func main() {
	// Intentionally empty: utility function implementation.
}

