package main

import (
	"bytes"
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
	"time"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	// Prevent unreasonable execution time / resource usage.
	if count > 100 {
		return 0, errors.New("count too large (max 100)")
	}

	// Basic allowlist to reduce command/option injection risk and weird parsing issues.
	// Allows typical hostnames, IPv4, IPv6 literals.
	if len(host) > 253 {
		return 0, errors.New("host too long")
	}
	hostRe := regexp.MustCompile(`^[a-zA-Z0-9.\-:]+$`)
	if !hostRe.MatchString(host) {
		return 0, errors.New("host contains invalid characters")
	}

	// Avoid shell execution. Pass arguments directly.
	// Use a timeout to avoid hanging indefinitely.
	timeout := time.Duration(count)*2*time.Second + 3*time.Second
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	var out bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &out

	if err := cmd.Start(); err != nil {
		return 0, fmt.Errorf("failed to start ping: %w", err)
	}

	done := make(chan error, 1)
	go func() { done <- cmd.Wait() }()

	select {
	case err := <-done:
		if err != nil {
			return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, out.String())
		}
	case <-time.After(timeout):
		_ = cmd.Process.Kill()
		<-done
		return 0, fmt.Errorf("ping timed out after %s", timeout)
	}

	outputStr := out.String()

	// Linux typically: "rtt min/avg/max/mdev = 12.345/23.456/34.567/5.678 ms"
	// macOS/BSD typically: "round-trip min/avg/max/stddev = 12.345/23.456/34.567/5.678 ms"
	re := regexp.MustCompile(`(?m)^(?:rtt|round-trip)[^=]*=\s*([\d.]+)/([\d.]+)/([\d.]+)/([\d.]+)\s*ms`)
	matches := re.FindStringSubmatch(outputStr)
	if len(matches) < 3 {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	avg, err := strconv.ParseFloat(matches[2], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}
	return avg, nil
}

func main() {
	// Intentionally empty: utility function implementation.
}

