package main

import (
	"bytes"
	"errors"
	"flag"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host must not be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be > 0")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		// Windows: -n <count>
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	default:
		// Linux/macOS: -c <count>
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var stderr bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &stderr

	if err := cmd.Run(); err != nil {
		msg := strings.TrimSpace(stderr.String())
		if msg == "" {
			msg = strings.TrimSpace(out.String())
		}
		if msg == "" {
			msg = err.Error()
		}
		return 0, fmt.Errorf("ping failed: %s", msg)
	}

	avg, err := parsePingAverage(out.String())
	if err != nil {
		return 0, err
	}
	return avg, nil
}

func parsePingAverage(output string) (float64, error) {
	// Linux: rtt min/avg/max/mdev = 12.345/23.456/...
	// macOS: round-trip min/avg/max/stddev = 12.345/23.456/...
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)[^=]*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)(?:/([0-9.]+))?\s*ms\s*$`)
	if m := reUnix.FindStringSubmatch(output); m != nil {
		avg, err := strconv.ParseFloat(m[2], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse avg latency: %w", err)
		}
		return avg, nil
	}

	// Windows (English): Average = 23ms
	reWin := regexp.MustCompile(`(?mi)\bAverage\s*=\s*([0-9]+)\s*ms\b`)
	if m := reWin.FindStringSubmatch(output); m != nil {
		avg, err := strconv.ParseFloat(m[1], 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse avg latency: %w", err)
		}
		return avg, nil
	}

	return 0, errors.New("could not parse average latency from ping output")
}

func main() {
	host := flag.String("host", "8.8.8.8", "Target host to ping (IP or hostname)")
	count := flag.Int("count", 4, "Number of ping attempts")
	flag.Parse()

	avg, err := MeasureLatency(*host, *count)
	if err != nil {
		fmt.Fprintln(os.Stderr, "Error:", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d ping(s): %.3f ms\n", *host, *count, avg)
}

