package main

import (
	"bytes"
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the given host `count` times and returns the average latency in milliseconds.
// It uses the system `ping` command via os/exec.
//
// Notes:
// - On Windows, it uses: ping -n <count> <host>
// - On Unix-like systems, it uses: ping -c <count> <host>
// - Requires the `ping` command to be available on PATH.
func MeasureLatency(host string, count int) (float64, error) {
	host = strings.TrimSpace(host)
	if host == "" {
		return 0, errors.New("host must not be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be > 0")
	}

	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	var out bytes.Buffer
	var errOut bytes.Buffer
	cmd.Stdout = &out
	cmd.Stderr = &errOut

	if err := cmd.Run(); err != nil {
		// ping often exits non-zero on packet loss; still try to parse output if present.
		if out.Len() == 0 {
			msg := strings.TrimSpace(errOut.String())
			if msg == "" {
				msg = err.Error()
			}
			return 0, fmt.Errorf("ping failed: %s", msg)
		}
	}

	avg, err := parseAverageLatencyMs(out.String())
	if err != nil {
		// include stderr if helpful
		msg := strings.TrimSpace(errOut.String())
		if msg != "" {
			return 0, fmt.Errorf("%w (stderr: %s)", err, msg)
		}
		return 0, err
	}
	return avg, nil
}

func parseAverageLatencyMs(output string) (float64, error) {
	// Linux/macOS typical:
	//   rtt min/avg/max/mdev = 12.345/23.456/34.567/1.234 ms
	// BusyBox sometimes:
	//   round-trip min/avg/max = 12.3/23.4/34.5 ms
	reUnix := regexp.MustCompile(`(?m)^(?:rtt|round-trip)[^=]*=\s*([0-9.]+)/([0-9.]+)/([0-9.]+)(?:/[0-9.]+)?\s*ms`)
	if m := reUnix.FindStringSubmatch(output); len(m) == 4 {
		avgStr := m[2]
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse unix avg latency %q: %w", avgStr, err)
		}
		return avg, nil
	}

	// Windows typical:
	//   Minimum = 1ms, Maximum = 3ms, Average = 2ms
	reWin := regexp.MustCompile(`(?mi)\bAverage\s*=\s*([0-9]+)\s*ms\b`)
	if m := reWin.FindStringSubmatch(output); len(m) == 2 {
		avgStr := m[1]
		avg, err := strconv.ParseFloat(avgStr, 64)
		if err != nil {
			return 0, fmt.Errorf("failed to parse windows avg latency %q: %w", avgStr, err)
		}
		return avg, nil
	}

	// Fallback: try to average per-packet "time=" occurrences (works for many ping variants).
	// Examples:
	//   time=23.4 ms
	//   time<1ms (Windows)
	reTime := regexp.MustCompile(`(?i)\btime[=<]\s*([0-9.]+)\s*ms\b`)
	matches := reTime.FindAllStringSubmatch(output, -1)
	if len(matches) > 0 {
		var sum float64
		var n int
		for _, m := range matches {
			if len(m) != 2 {
				continue
			}
			v, err := strconv.ParseFloat(m[1], 64)
			if err != nil {
				continue
			}
			sum += v
			n++
		}
		if n > 0 {
			return sum / float64(n), nil
		}
	}

	return 0, errors.New("could not parse average latency from ping output")
}

func main() {
	// Simple CLI:
	//   go run . <host> <count>
	// Example:
	//   go run . 8.8.8.8 5
	host := "8.8.8.8"
	count := 4

	if len(os.Args) >= 2 {
		host = os.Args[1]
	}
	if len(os.Args) >= 3 {
		c, err := strconv.Atoi(os.Args[2])
		if err != nil {
			fmt.Fprintf(os.Stderr, "invalid count: %v\n", err)
			os.Exit(2)
		}
		count = c
	}

	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Fprintf(os.Stderr, "MeasureLatency error: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s over %d pings: %.3f ms\n", host, count, avg)
}

